import api from './api';

export const getChansons = () => api.get('/chansons');
export const getChanson = (id) => api.get(`/chansons/${id}`);
export const createChanson = (data) => api.post('/chansons', data);
export const createChansonSpecial = (data) => api.post('/chansons/create', data);
export const updateChanson = (id, data) => api.put(`/chansons/${id}`, data);
export const deleteChanson = (id) => api.delete(`/chansons/${id}`);
